import java.util.Scanner;
import java.nio.charset.StandardCharsets;

public class SafeBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Validate input length to prevent buffer overflow
        if (input.length() > 10) {
            System.out.println("Input string is too long. Please enter a string with 10 characters or less.");
            return;
        }

        byte[] buffer = new byte[10];
        byte[] inputBytes = input.getBytes(StandardCharsets.UTF_8);

        // Copy input bytes into buffer
        System.arraycopy(inputBytes, 0, buffer, 0, Math.min(inputBytes.length, buffer.length));

        System.out.println("Input: " + new String(buffer, StandardCharsets.UTF_8).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
